 Begin CmpMap 	# Compound Mapping
    Nin = 1 	# Number of input coordinates
 IsA Mapping 	# Mapping between coordinate systems
    InvB = 1 	# Second Mapping used in inverse direction
    MapA = 	# First component Mapping
       Begin TimeMap 	# Conversion between time coordinate systems
          Nin = 1 	# Number of input coordinates
          IsSimp = 1 	# Mapping has been simplified
       IsA Mapping 	# Mapping between coordinate systems
          Ntime = 1 	# Number of conversion steps
          Time1 = "TTTOTDB" 	# Convert TT to TDB
          Time1a = 0 	# MJD offset
          Time1b = 0 	# Observer longitude
          Time1c = 0 	# Observer latitude
          Time1d = 0 	# Observer altitude
          Time1e = 6378.1369999999997 	# Distance from earth spin axis
          Time1f = 0 	# Distance north of equatorial plane
          Time1g = 37 	# DTAI
       End TimeMap
    MapB = 	# Second component Mapping
       Begin TimeMap 	# Conversion between time coordinate systems
          Nin = 1 	# Number of input coordinates
          Invert = 1 	# Mapping inverted
       IsA Mapping 	# Mapping between coordinate systems
          Ntime = 1 	# Number of conversion steps
          Time1 = "TTTOTDB" 	# Convert TT to TDB
          Time1a = 0 	# MJD offset
          Time1b = 0 	# Observer longitude
          Time1c = 0 	# Observer latitude
          Time1d = 0 	# Observer altitude
          Time1e = 6378.1369999999997 	# Distance from earth spin axis
          Time1f = 0 	# Distance north of equatorial plane
          Time1g = 37 	# DTAI
       End TimeMap
 End CmpMap
